import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { TradeResultParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/TradeResultParser';

export class TradeResultEvent extends MessageEvent implements IMessageEvent
{
constructor(callback: Function)
{
super(callback, TradeResultParser);
}

public getParser(): TradeResultParser
{
return this.parser as TradeResultParser;
}
}